{
  "name": "Action Divers & Adventures - Luxury Belize Expeditions",
  "description": "A high-end 'Quiet Luxury' digital experience for Belizean adventures, featuring a Glassmorphism aesthetic and a sophisticated AI concierge.",
  "requestFramePermissions": ["camera", "microphone"]
}

export interface Tour {
  id: string;
  name: string;
  description: string;
  longDescription: string;
  category: 'island' | 'mainland';
  subCategory?: string;
  isAvailable: boolean;
  image: string;
  features?: string[];
}

export interface BlogLog {
  id: string;
  title: string;
  date: string;
  content: string;
  imageUrl: string;
}

export interface User {
  username: string;
  isAuthenticated: boolean;
}

import { GoogleGenAI } from "@google/genai";
import { INITIAL_TOURS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are the "Tour Assistant" for Action Divers & Adventures in Belize. 
Your tone must be sophisticated, welcoming, and knowledgeable (Quiet Luxury vibe).

SOLE SOURCE OF TRUTH:
You must use the following content as your primary knowledge base. If asked about tours, diving sites, or mainland adventures, use the specific details and exact wording provided here.

${JSON.stringify(INITIAL_TOURS)}

Details to include when asked:
- Diving Sites: Palmeros Point (overhangs, Horse Eye Jacks), Love Tunnel (weddings, Spotted Drums), Angel Flats (Queen Angels), Amigos Wreck (40ft cargo ship, nurse sharks), Eagle Ray Canyon, Cypress Garden.
- Snorkeling: Hol Chan, Shark-Ray Alley, Mexico Rocks.
- Mainland: Lamanai (Jaguar Temple, Mask Temple, El Castillo), ATM Caves (skeletons, ceramics), Cave Tubing & Zip-lining.

GUIDELINES:
- Be concise but elegant.
- If you don't know something from the text, you may use your internal knowledge about Belize, but prefix it by saying "Beyond our curated experiences, I can also share that..."
- Never mention your underlying AI model.
- You represent Action Divers & Adventures.
`;

export async function getAssistantResponse(message: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.95,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I apologize, my connection to the mainland is slightly interrupted. How else can I assist your luxury expedition planning?";
  }
}

