import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, X, Send, Sparkles } from 'lucide-react';
import { getAssistantResponse } from '../services/geminiService';

const TourAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; content: string }[]>([
    { role: 'assistant', content: "Welcome to Action Divers. I am your Tour Assistant. How can I help you discover the magic of Belize today?" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsTyping(true);

    const response = await getAssistantResponse(userMsg);
    setMessages(prev => [...prev, { role: 'assistant', content: response || "I'm sorry, I couldn't process that." }]);
    setIsTyping(false);
  };

  return (
    <div className="fixed bottom-8 right-8 z-[60]">
      {!isOpen ? (
        <button
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 rounded-full bg-gradient-to-tr from-[#005F73] to-[#E9D8A6] flex items-center justify-center shadow-2xl hover:scale-110 transition-transform animate-pulse"
        >
          <Sparkles className="text-[#001219] w-8 h-8" />
        </button>
      ) : (
        <div className="w-[380px] h-[550px] glass rounded-3xl flex flex-col overflow-hidden shadow-2xl border border-white/20 animate-fade-in">
          <div className="p-5 flex justify-between items-center border-b border-white/10 bg-white/5">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 rounded-full bg-[#E9D8A6] flex items-center justify-center">
                <Sparkles className="text-[#001219] w-5 h-5" />
              </div>
              <div>
                <h3 className="serif text-[#E9D8A6] font-bold">Tour Assistant</h3>
                <p className="text-[10px] text-[#E9D8A6]/60 uppercase tracking-tighter">Concierge Service</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-[#E9D8A6]/60 hover:text-[#E9D8A6]">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div 
                  className={`max-w-[85%] p-4 rounded-2xl text-sm leading-relaxed ${
                    m.role === 'user' 
                    ? 'bg-[#005F73] text-white rounded-tr-none' 
                    : 'bg-white/10 text-[#E9D8A6] rounded-tl-none border border-white/10'
                  }`}
                >
                  {m.content}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex justify-start">
                <div className="bg-white/10 p-3 rounded-2xl rounded-tl-none border border-white/10 animate-pulse text-[#E9D8A6]/60 text-xs">
                  Writing...
                </div>
              </div>
            )}
          </div>

          <div className="p-4 border-t border-white/10 bg-white/5 flex space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Inquire about our tours..."
              className="flex-1 bg-white/5 border border-white/10 rounded-full px-4 py-2 text-sm text-[#E9D8A6] focus:outline-none focus:border-[#E9D8A6]/40"
            />
            <button
              onClick={handleSend}
              className="w-10 h-10 rounded-full bg-[#E9D8A6] text-[#001219] flex items-center justify-center hover:bg-[#E9D8A6]/80"
            >
              <Send className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default TourAssistant;

import React, { useState } from 'react';
import { INITIAL_TOURS, INITIAL_LOGS } from '../constants';
import { LogOut, Plus, Trash2, Edit2, CheckCircle, XCircle } from 'lucide-react';

const Admin: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [tours, setTours] = useState(INITIAL_TOURS);
  const [logs, setLogs] = useState(INITIAL_LOGS);

  // New Log Form State
  const [newLog, setNewLog] = useState({ title: '', content: '', imageUrl: '' });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'admin' && password === 'belize2024') {
      setIsLoggedIn(true);
    } else {
      alert('Invalid credentials');
    }
  };

  const toggleAvailability = (id: string) => {
    setTours(tours.map(t => t.id === id ? { ...t, isAvailable: !t.isAvailable } : t));
  };

  const handleAddLog = (e: React.FormEvent) => {
    e.preventDefault();
    const log = {
      ...newLog,
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0]
    };
    setLogs([log, ...logs]);
    setNewLog({ title: '', content: '', imageUrl: '' });
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen flex items-center justify-center px-4">
        <div className="glass p-12 rounded-3xl w-full max-w-md border border-white/10">
          <h2 className="text-3xl serif text-center mb-8">Owner Login</h2>
          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-xs uppercase tracking-widest mb-2 text-[#E9D8A6]/60">Username</label>
              <input 
                type="text" 
                className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-[#E9D8A6]"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs uppercase tracking-widest mb-2 text-[#E9D8A6]/60">Password</label>
              <input 
                type="password" 
                className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-[#E9D8A6]"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>
            <button className="w-full bg-[#E9D8A6] text-[#001219] font-bold py-4 rounded-full uppercase tracking-widest hover:bg-white transition-all">
              Enter Dashboard
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="pt-32 pb-20 max-w-7xl mx-auto px-4">
      <div className="flex justify-between items-center mb-12">
        <h1 className="text-4xl serif">Command Centre</h1>
        <button onClick={() => setIsLoggedIn(false)} className="flex items-center space-x-2 text-[#E9D8A6]/60 hover:text-white">
          <LogOut className="w-5 h-5" />
          <span>Sign Out</span>
        </button>
      </div>

      <div className="grid lg:grid-cols-2 gap-12">
        {/* Manage Tours */}
        <section>
          <h2 className="text-2xl serif mb-6 flex items-center space-x-3">
            <div className="w-2 h-2 bg-[#005F73] rounded-full"></div>
            <span>Inventory Management</span>
          </h2>
          <div className="glass rounded-3xl divide-y divide-white/5 overflow-hidden">
            {tours.map(tour => (
              <div key={tour.id} className="p-6 flex items-center justify-between hover:bg-white/5 transition-colors">
                <div>
                  <h4 className="font-bold text-[#E9D8A6]">{tour.name}</h4>
                  <p className="text-xs text-[#E9D8A6]/40 uppercase tracking-tighter">{tour.category}</p>
                </div>
                <button 
                  onClick={() => toggleAvailability(tour.id)}
                  className={`flex items-center space-x-2 px-4 py-2 rounded-full text-xs font-bold transition-all ${
                    tour.isAvailable 
                    ? 'bg-green-500/10 text-green-400 border border-green-500/20' 
                    : 'bg-red-500/10 text-red-400 border border-red-500/20'
                  }`}
                >
                  {tour.isAvailable ? <CheckCircle className="w-3 h-3" /> : <XCircle className="w-3 h-3" />}
                  <span>{tour.isAvailable ? 'AVAILABLE' : 'BOOKED'}</span>
                </button>
              </div>
            ))}
          </div>
        </section>

        {/* Voyage Chronicles */}
        <section>
          <h2 className="text-2xl serif mb-6 flex items-center space-x-3">
            <div className="w-2 h-2 bg-[#005F73] rounded-full"></div>
            <span>Voyage Chronicles</span>
          </h2>
          <div className="glass p-8 rounded-3xl mb-8">
            <h3 className="text-lg serif mb-6">New Chronicle Log</h3>
            <form onSubmit={handleAddLog} className="space-y-4">
              <input 
                placeholder="Log Title" 
                className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-sm"
                value={newLog.title}
                onChange={e => setNewLog({...newLog, title: e.target.value})}
                required
              />
              <input 
                placeholder="Image URL" 
                className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-sm"
                value={newLog.imageUrl}
                onChange={e => setNewLog({...newLog, imageUrl: e.target.value})}
              />
              <textarea 
                placeholder="Story from the sea..." 
                className="w-full bg-white/5 border border-white/10 rounded-lg p-3 text-sm h-32"
                value={newLog.content}
                onChange={e => setNewLog({...newLog, content: e.target.value})}
                required
              ></textarea>
              <button className="bg-[#005F73] text-white px-8 py-3 rounded-full text-sm font-bold uppercase tracking-widest hover:bg-[#005F73]/80 transition-all flex items-center">
                <Plus className="w-4 h-4 mr-2" /> Publish Log
              </button>
            </form>
          </div>

          <div className="space-y-4">
            {logs.map(log => (
              <div key={log.id} className="glass p-5 rounded-2xl flex items-center justify-between">
                <div className="flex items-center space-x-4">
                  <img src={log.imageUrl || 'https://picsum.photos/100'} className="w-12 h-12 rounded-lg object-cover" />
                  <div>
                    <h4 className="font-bold text-sm">{log.title}</h4>
                    <p className="text-[10px] text-[#E9D8A6]/40 uppercase">{log.date}</p>
                  </div>
                </div>
                <div className="flex space-x-2">
                  <button className="p-2 text-[#E9D8A6]/40 hover:text-white"><Edit2 className="w-4 h-4" /></button>
                  <button className="p-2 text-red-500/40 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
};

export default Admin;

