import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { INITIAL_TOURS } from '../constants';
import { MapPin, CheckCircle2, Calendar, XCircle, DollarSign } from 'lucide-react';
import { Tour } from '../types';

const TourDetail: React.FC = () => {
  const { id } = useParams();
  const [tour, setTour] = useState<Tour | undefined>(undefined);

  useEffect(() => {
    const updateTourData = () => {
      // 1. Find the base tour data from our constants
      const baseTour = INITIAL_TOURS.find(t => t.id === id);

      if (baseTour) {
        // 2. Fetch the latest availability from localStorage
        const storedToursStatus = localStorage.getItem('action_divers_tours_status');
        let currentAvailability = baseTour.isAvailable;

        if (storedToursStatus) {
          const statusMap = JSON.parse(storedToursStatus);
          if (statusMap[baseTour.id] !== undefined) {
            currentAvailability = statusMap[baseTour.id];
          }
        }

        // 3. Set the state with the full updated object
        setTour({ ...baseTour, isAvailable: currentAvailability });
      } else {
        setTour(undefined);
      }
    };

    updateTourData();

    // Listen for storage changes (e.g. from Admin panel in another tab/window)
    window.addEventListener('storage', updateTourData);
    return () => window.removeEventListener('storage', updateTourData);
  }, [id]);

  if (!tour) return (
    <div className="h-screen flex items-center justify-center bg-[#001219]">
      <h2 className="text-4xl serif text-[#E9D8A6]">Expedition not found.</h2>
    </div>
  );

  return (
    <div className="pt-20">
      <div className="relative h-[60vh]">
        <img src={tour.image} alt={tour.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-t from-[#001219] to-transparent"></div>
        <div className="absolute bottom-20 left-0 right-0 max-w-7xl mx-auto px-4">
          <span className="text-[#E9D8A6] uppercase tracking-[0.4em] text-xs block mb-4">{tour.category} Adventure</span>
          <h1 className="text-6xl md:text-8xl serif text-[#E9D8A6]">{tour.name}</h1>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-20 text-[#E9D8A6]">
        <div className="grid lg:grid-cols-3 gap-16">
          <div className="lg:col-span-2 space-y-12">
            <section>
              <h2 className="text-3xl serif mb-6 text-[#E9D8A6]">The Experience</h2>
              <p className="text-xl leading-relaxed text-[#E9D8A6]/80 font-light">
                {tour.longDescription}
              </p>
            </section>

            {tour.features && (
              <section className="glass p-10 rounded-3xl">
                <h3 className="text-2xl serif mb-8">Notable Highlights</h3>
                <div className="grid md:grid-cols-2 gap-6">
                  {tour.features.map((feature, i) => (
                    <div key={i} className="flex items-start space-x-3">
                      <div className="mt-1 w-5 h-5 rounded-full bg-[#005F73]/30 flex items-center justify-center shrink-0">
                        <div className="w-2 h-2 rounded-full bg-[#E9D8A6]"></div>
                      </div>
                      <span className="text-lg text-[#E9D8A6]/90">{feature}</span>
                    </div>
                  ))}
                </div>
              </section>
            )}
          </div>

          <aside className="space-y-8">
            <div className="glass p-8 rounded-3xl sticky top-32 border border-[#E9D8A6]/10">
              <h3 className="text-2xl serif mb-6">Booking Details</h3>

              <div className="space-y-6 mb-10">
                <div className="flex items-center text-[#E9D8A6]/70">
                  {tour.isAvailable ? (
                    <CheckCircle2 className="w-5 h-5 mr-3 text-green-500" />
                  ) : (
                    <XCircle className="w-5 h-5 mr-3 text-red-500" />
                  )}
                  <span className={tour.isAvailable ? 'text-green-400' : 'text-red-400 font-bold'}>
                    {tour.isAvailable ? 'Available for booking' : 'FULLY BOOKED'}
                  </span>
                </div>
                <div className="flex items-center text-[#E9D8A6]/70">
                  <DollarSign className="w-5 h-5 mr-3 text-[#005F73]" />
                  <span>Starting at ${tour.price} USD</span>
                </div>
                <div className="flex items-center text-[#E9D8A6]/70">
                  <MapPin className="w-5 h-5 mr-3 text-[#005F73]" />
                  <span>Ambergris Caye, Belize</span>
                </div>
                <div className="flex items-center text-[#E9D8A6]/70">
                  <Calendar className="w-5 h-5 mr-3 text-[#005F73]" />
                  <span>Daily departures</span>
                </div>
              </div>

              {tour.isAvailable ? (
                <a 
                  href="#/reservations" 
                  className="block w-full text-center bg-[#E9D8A6] text-[#001219] py-4 rounded-full font-bold uppercase tracking-widest hover:bg-white transition-all shadow-xl"
                >
                  Inquire Now
                </a>
              ) : (
                <div className="w-full text-center bg-white/5 text-[#E9D8A6]/20 py-4 rounded-full font-bold uppercase tracking-widest border border-white/5">
                  Temporarily unavailable
                </div>
              )}
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

