const ScrollToTop = () => {
  const { pathname } = useLocation();
  React.useEffect(() => {
    try {
      window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
    } catch (e) {
      window.scrollTo(0, 0);
    }
  }, [pathname]);
  return null;
};

const Reservations = () => {
  const [availableTours, setAvailableTours] = useState<Tour[]>(INITIAL_TOURS);
  const [selectedTours, setSelectedTours] = useState<string[]>([]);
  const [totalPrice, setTotalPrice] = useState(0);

  useEffect(() => {
    const loadAvailability = () => {
      const storedToursStatus = localStorage.getItem('action_divers_tours_status');
      if (storedToursStatus) {
        const statusMap = JSON.parse(storedToursStatus);
        const filtered = INITIAL_TOURS.map(t => ({
          ...t,
          isAvailable: statusMap[t.id] !== undefined ? statusMap[t.id] : t.isAvailable
        })).filter(t => t.isAvailable);
        setAvailableTours(filtered);
      } else {
        setAvailableTours(INITIAL_TOURS.filter(t => t.isAvailable));
      }
    };

    loadAvailability();
    window.addEventListener('storage', loadAvailability);
    return () => window.removeEventListener('storage', loadAvailability);
  }, []);

  useEffect(() => {
    const total = availableTours
      .filter(t => selectedTours.includes(t.id))
      .reduce((sum, t) => sum + t.price, 0);
    setTotalPrice(total);
  }, [selectedTours, availableTours]);

  const toggleTourSelection = (id: string) => {
    setSelectedTours(prev => 
      prev.includes(id) ? prev.filter(t => t !== id) : [...prev, id]
    );
  };

  return (
    <div className="pt-48 pb-32 max-w-4xl mx-auto px-6 text-center">
      <h1 className="text-6xl md:text-7xl serif mb-6 text-[#E9D8A6]">Contact <span className="italic">Us</span></h1>
      <p className="text-[#E9D8A6]/60 mb-16 italic text-lg uppercase tracking-widest">Reserve Your Bespoke Experience</p>

