          <p className="text-center text-[#E9D8A6]/40 text-xs uppercase tracking-widest mb-8">Choose one or multiple expeditions</p>

          <div className="grid sm:grid-cols-2 gap-4">
            {availableTours.map((tour) => (
              <button
                key={tour.id}
                type="button"
                onClick={() => toggleTourSelection(tour.id)}
                className={`group relative p-5 rounded-2xl border transition-all text-left flex items-start gap-4 ${
                  selectedTours.includes(tour.id)
                    ? 'bg-[#E9D8A6] border-[#E9D8A6] shadow-[0_0_20px_rgba(233,216,166,0.3)]'
                    : 'bg-white/5 border-white/10 hover:border-white/20'
                }`}
              >
                <div className={`w-6 h-6 rounded-full border-2 shrink-0 flex items-center justify-center transition-colors ${
                  selectedTours.includes(tour.id) ? 'bg-[#001219] border-[#001219]' : 'border-white/20'
                }`}>
                  {selectedTours.includes(tour.id) && <Check className="w-3 h-3 text-[#E9D8A6]" />}
                </div>
                <div className="flex-1">
                  <h4 className={`text-sm font-bold uppercase tracking-widest ${selectedTours.includes(tour.id) ? 'text-[#001219]' : 'text-[#E9D8A6]'}`}>
                    {tour.name}
                  </h4>
                  <p className={`text-[10px] mt-1 ${selectedTours.includes(tour.id) ? 'text-[#001219]/60' : 'text-[#E9D8A6]/40'}`}>
                    ${tour.price.toFixed(2)} USD / Person
                  </p>
                </div>
              </button>
            ))}
          </div>

          {selectedTours.length > 0 && (
            <div className="mt-8 p-6 bg-white/5 rounded-3xl border border-white/10 animate-fade-in">
              <div className="flex justify-between items-end">
                <div>
                  <p className="text-[10px] uppercase tracking-widest text-[#E9D8A6]/40 mb-1 font-bold">Estimated Base Cost</p>
                  <p className="text-3xl serif text-[#E9D8A6]">${totalPrice.toFixed(2)} <span className="text-sm font-sans font-light uppercase tracking-widest text-[#E9D8A6]/40 ml-2">USD total</span></p>
                </div>
                <div className="text-right hidden sm:block">
                  <p className="text-[9px] uppercase tracking-[0.3em] text-[#E9D8A6]/20">Final pricing confirmed by guide</p>
                </div>
              </div>
            </div>
          )}
