    },
    { 
      name: 'Mainland Adventures', 
      path: '/mainland-adventures',
      icon: <Map className="w-5 h-5" />,
      items: [
        { name: 'Cave Tubing / Zip-lining', path: '/tour/cave-tubing-ziplining' },
        { name: 'Lamanai', path: '/tour/lamanai' },
        { name: 'ATM Caves', path: '/tour/atm-caves' },
